{{/if}}{{if::{{eq::{{var::length}}::{{varDefault::length}}}}}}{{else}}[LENGTH] {{var::length}}
{{/if}}{{if::{{eq::{{var::genre}}::none}}}}{{else}}[GENRE — what this beat should weight and how it should move] {{var::genre}}
{{/if}}{{if::{{eq::{{var::prose}}::}}}}{{else}}[REGISTER — hold it every sentence, from the first line] {{var::prose}}
{{/if}}{{if::{{eq::{{var::pacing}}::{{varDefault::pacing}}}}}}{{else}}[PACING] {{var::pacing}}
{{/if}}{{if::{{eq::{{var::distance}}::{{varDefault::distance}}}}}}{{else}}[DISTANCE] {{var::distance}}
{{/if}}{{if::{{eq::{{var::dialogue}}::{{varDefault::dialogue}}}}}}{{else}}[DIALOGUE MIX] {{var::dialogue}}
{{/if}}{{if::{{eq::{{var::tense}}::{{varDefault::tense}}}}}}{{else}}[TENSE] {{var::tense}}
{{/if}}{{if::{{eq::{{var::cast}}::none}}}}{{else}}[TONAL WASH — the emotional wavelength this scene is filtered through] {{var::cast}}
{{/if}}{{/if}}
